#!/usr/bin/env python3
from pathlib import Path
import base64
import sys

TARGET = Path("src/clone/replay-observed-overrides.ts")
CONTENT_B64 = """"""

if not TARGET.exists():
    print(f"ERROR: {TARGET} not found. Run this from the repo root.", file=sys.stderr)
    sys.exit(1)

current = TARGET.read_text()
if "inferRandomDamageTargetFromPostState" not in current or "withReplayObservedTargets" not in current:
    print(f"ERROR: {TARGET} does not look like the expected replay override file.", file=sys.stderr)
    sys.exit(1)

backup = TARGET.with_suffix(TARGET.suffix + ".bak_before_random_overlap")
backup.write_text(current)
TARGET.write_bytes(base64.b64decode(CONTENT_B64))

print(f"Wrote {TARGET}")
print(f"Backup: {backup}")
print("Next: run the fixture state-diff command and verify totalDiffs drops from 5.")
